{
  "name": "Smart Insurance PDF Extractor",
  "description": "An advanced tool to extract data from car insurance PDFs, manage details, and create customizable A4 print layouts with drag-and-drop functionality.",
  "requestFramePermissions": []
}

export interface InsuranceData {
  qrCode: string;
  serialNumber: string;
  ownerName: string;
  address: string;
  licensePlate: string;
  chassisNumber: string;
  engineNumber: string;
  vehicleType: string;
  weight: string;
  seats: string;
  purpose: string;
  term: string;
  fee: string;
}

export interface PrintableElement {
  id: string;
  key: keyof InsuranceData;
  label: string;
  x: number;
  y: number;
  fontSize: number;
  fontWeight: string;
  isVisible: boolean;
}

export type TabType = 'list' | 'print';

import { GoogleGenAI, Type } from "@google/genai";
import { InsuranceData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const extractInsuranceData = async (fileBase64: string, mimeType: string): Promise<InsuranceData> => {
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model: model,
    contents: [
      {
        parts: [
          {
            text: "Analyze this insurance document and extract the following details into a JSON object. Fields: qrCode (the string encoded in the QR code if visible), serialNumber (Số seri), ownerName (Tên chủ xe), address (Địa chỉ), licensePlate (Biển số), chassisNumber (Số khung), engineNumber (Số máy), vehicleType (Loại xe), weight (Trọng tải), seats (Số chỗ), purpose (Mục đích sử dụng), term (Thời hạn bảo hiểm), fee (Phí bảo hiểm). Use Vietnamese for values where appropriate. If a value is missing, return empty string."
          },
          {
            inlineData: {
              data: fileBase64,
              mimeType: mimeType
            }
          }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          qrCode: { type: Type.STRING },
          serialNumber: { type: Type.STRING },
          ownerName: { type: Type.STRING },
          address: { type: Type.STRING },
          licensePlate: { type: Type.STRING },
          chassisNumber: { type: Type.STRING },
          engineNumber: { type: Type.STRING },
          vehicleType: { type: Type.STRING },
          weight: { type: Type.STRING },
          seats: { type: Type.STRING },
          purpose: { type: Type.STRING },
          term: { type: Type.STRING },
          fee: { type: Type.STRING },
        },
        required: ["serialNumber", "ownerName"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}') as InsuranceData;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Dữ liệu trả về không hợp lệ");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { QRCodeSVG } from 'qrcode.react';
import { PrintableElement } from '../types';

interface DraggableItemProps {
  element: PrintableElement;
  value: string;
  onUpdate: (id: string, updates: Partial<PrintableElement>) => void;
  containerRef: React.RefObject<HTMLDivElement>;
  isEditing: boolean;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ 
  element, 
  value, 
  onUpdate, 
  containerRef,
  isEditing
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragRef = useRef<{ startX: number; startY: number; initialX: number; initialY: number } | null>(null);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!isEditing) return;
    setIsDragging(true);
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      initialX: element.x,
      initialY: element.y
    };
    e.preventDefault();
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging || !dragRef.current || !containerRef.current) return;

      const deltaX = e.clientX - dragRef.current.startX;
      const deltaY = e.clientY - dragRef.current.startY;

      const containerRect = containerRef.current.getBoundingClientRect();

      let newX = dragRef.current.initialX + deltaX;
      let newY = dragRef.current.initialY + deltaY;

      // Contain within parent
      newX = Math.max(0, Math.min(newX, containerRect.width - 50));
      newY = Math.max(0, Math.min(newY, containerRect.height - 20));

      onUpdate(element.id, { x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, onUpdate, element.id, containerRef]);

  if (!element.isVisible) return null;

  return (
    <div
      style={{
        position: 'absolute',
        left: `${element.x}px`,
        top: `${element.y}px`,
        fontSize: `${element.fontSize}px`,
        fontWeight: element.fontWeight,
        cursor: isEditing ? 'move' : 'default',
        userSelect: 'none',
        zIndex: isDragging ? 50 : 10,
        backgroundColor: isDragging ? 'rgba(59, 130, 246, 0.1)' : 'transparent',
        border: isEditing ? '1px dashed #d1d5db' : 'none',
        padding: isEditing ? '2px' : '0'
      }}
      onMouseDown={handleMouseDown}
      className="transition-colors duration-150"
    >
      {element.key === 'qrCode' ? (
        value ? (
          <div className="bg-white p-1 inline-block border">
             <QRCodeSVG value={value} size={80} />
          </div>
        ) : (
          isEditing && <div className="w-20 h-20 bg-gray-100 flex items-center justify-center text-[10px] text-gray-400">QR Area</div>
        )
      ) : (
        <span>{value || (isEditing ? `[${element.label}]` : '')}</span>
      )}
    </div>
  );
};

import React, { useState, useCallback, useRef } from 'react';
import { 
  FileText, 
  Printer, 
  Layout, 
  List, 
  Upload, 
  Download, 
  Edit3, 
  Plus, 
  Trash2,
  Settings,
  AlertCircle,
  Loader2,
  ChevronRight,
  ChevronLeft
} from 'lucide-react';
import { InsuranceData, PrintableElement, TabType } from './types';
import { DEFAULT_ELEMENTS, EMPTY_INSURANCE } from './constants';
import { extractInsuranceData } from './services/geminiService';
import { DraggableItem } from './components/DraggableItem';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('list');
  const [data, setData] = useState<InsuranceData>(EMPTY_INSURANCE);
  const [elements, setElements] = useState<PrintableElement[]>(DEFAULT_ELEMENTS);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isEditingLayout, setIsEditingLayout] = useState(false);
  const [pdfLink, setPdfLink] = useState('');

  const containerRef = useRef<HTMLDivElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        try {
          const result = await extractInsuranceData(base64, file.type);
          setData(result);
        } catch (err: any) {
          setError(err.message || "Không thể trích xuất dữ liệu");
        } finally {
          setIsLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Lỗi đọc file");
      setIsLoading(false);
    }
  };

  const handleUrlUpload = async () => {
    if (!pdfLink) return;
    setIsLoading(true);
    setError(null);
    try {
      // In a real browser environment, direct fetching might hit CORS.
      // We will simulate fetching by warning user or assuming proxy works.
      const response = await fetch(pdfLink);
      const blob = await response.blob();
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        const result = await extractInsuranceData(base64, blob.type);
        setData(result);
        setIsLoading(false);
      };
      reader.readAsDataURL(blob);
    } catch (err) {
      setError("Không thể tải PDF từ link. Hãy thử tải file lên trực tiếp.");
      setIsLoading(false);
    }
  };

  const updateElement = useCallback((id: string, updates: Partial<PrintableElement>) => {
    setElements(prev => prev.map(el => el.id === id ? { ...el, ...updates } : el));
  }, []);

  const handlePrint = () => {
    window.print();
  };

  const handleDataChange = (key: keyof InsuranceData, value: string) => {
    setData(prev => ({ ...prev, [key]: value }));
  };

  const resetLayout = () => {
    setElements(DEFAULT_ELEMENTS);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header - No Print */}
      <header className="no-print bg-white border-b sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="bg-blue-600 p-2 rounded-lg text-white">
              <FileText size={24} />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-gray-800">InsureExtract</h1>
          </div>

          <div className="flex-1 max-w-xl mx-8">
            <div className="relative group">
              <input
                type="text"
                placeholder="Nhập link PDF bảo hiểm..."
                className="w-full pl-4 pr-24 py-2 bg-gray-100 border-none rounded-full focus:ring-2 focus:ring-blue-500 transition-all text-sm"
                value={pdfLink}
                onChange={(e) => setPdfLink(e.target.value)}
              />
              <button 
                onClick={handleUrlUpload}
                disabled={isLoading}
                className="absolute right-1 top-1 bottom-1 px-4 bg-blue-600 text-white rounded-full text-xs font-medium hover:bg-blue-700 disabled:opacity-50"
              >
                {isLoading ? <Loader2 className="animate-spin" size={16} /> : 'Tải link'}
              </button>
            </div>
          </div>

          <div className="flex items-center space-x-3">
            <label className="flex items-center space-x-2 px-4 py-2 bg-gray-100 hover:bg-gray-200 rounded-lg cursor-pointer transition-colors text-sm font-medium">
              <Upload size={18} />
              <span>Tải file</span>
              <input type="file" className="hidden" accept="application/pdf,image/*" onChange={handleFileUpload} />
            </label>
            <button 
              onClick={handlePrint}
              className="flex items-center space-x-2 px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg transition-colors text-sm font-medium shadow-sm shadow-blue-200"
            >
              <Printer size={18} />
              <span>In PDF</span>
            </button>
          </div>
        </div>
      </header>

      {/* Tabs - No Print */}
      <div className="no-print bg-white border-b sticky top-16 z-40">
        <div className="max-w-7xl mx-auto px-4">
          <nav className="flex space-x-8">
            <button
              onClick={() => setActiveTab('list')}
              className={`py-4 px-2 border-b-2 font-medium text-sm flex items-center space-x-2 transition-colors ${
                activeTab === 'list' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              <List size={18} />
              <span>Dữ liệu trích xuất</span>
            </button>
            <button
              onClick={() => setActiveTab('print')}
              className={`py-4 px-2 border-b-2 font-medium text-sm flex items-center space-x-2 transition-colors ${
                activeTab === 'print' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              <Layout size={18} />
              <span>Bản in A4</span>
            </button>
          </nav>
        </div>
      </div>

      {/* Main Content */}
      <main className="flex-1 overflow-auto bg-gray-50 p-6">
        <div className="max-w-7xl mx-auto">
          {error && (
            <div className="no-print mb-6 p-4 bg-red-50 border border-red-200 rounded-xl flex items-center space-x-3 text-red-700">
              <AlertCircle size={20} />
              <p className="text-sm">{error}</p>
            </div>
          )}

          {isLoading && (
            <div className="no-print fixed inset-0 bg-white/60 backdrop-blur-sm z-50 flex flex-col items-center justify-center">
              <div className="bg-white p-8 rounded-2xl shadow-xl flex flex-col items-center border">
                <Loader2 className="animate-spin text-blue-600 mb-4" size={48} />
                <h3 className="text-lg font-semibold text-gray-800">Đang trích xuất dữ liệu</h3>
                <p className="text-gray-500 text-sm mt-1 text-center">Gemini AI đang phân tích nội dung văn bản...</p>
              </div>
            </div>
          )}

          {activeTab === 'list' ? (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="bg-white rounded-2xl shadow-sm border p-6">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-lg font-bold text-gray-800 flex items-center space-x-2">
                    <Edit3 size={20} className="text-blue-600" />
                    <span>Thông tin bảo hiểm</span>
                  </h3>
                  <button onClick={() => setData(EMPTY_INSURANCE)} className="text-xs text-red-500 hover:underline">Xóa tất cả</button>
                </div>

                <div className="space-y-4">
                  {Object.entries(data).map(([key, value]) => (
                    <div key={key} className="space-y-1">
                      <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">{key}</label>
                      <input
                        type="text"
                        value={value}
                        onChange={(e) => handleDataChange(key as keyof InsuranceData, e.target.value)}
                        className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 transition-all text-sm"
                        placeholder={`Nhập ${key}...`}
                      />
                    </div>
                  ))}
                </div>
              </div>

              <div className="hidden lg:block bg-blue-50 rounded-2xl border border-blue-100 p-8 flex flex-col items-center justify-center text-center">
                <div className="bg-white p-6 rounded-full shadow-lg shadow-blue-100 mb-6">
                  <FileText size={64} className="text-blue-600" />
                </div>
                <h2 className="text-2xl font-bold text-gray-800 mb-2">Chỉnh sửa & Kiểm tra</h2>
                <p className="text-gray-600 max-w-sm">Dữ liệu được trích xuất tự động bằng trí tuệ nhân tạo. Hãy kiểm tra lại độ chính xác trước khi chuyển sang tab in.</p>
                <div className="mt-8 flex space-x-4">
                   <div className="bg-white px-4 py-2 rounded-lg text-xs font-medium text-blue-700 border border-blue-200 shadow-sm">AI Powered Extraction</div>
                   <div className="bg-white px-4 py-2 rounded-lg text-xs font-medium text-blue-700 border border-blue-200 shadow-sm">Instant Sync to Print</div>
                </div>
              </div>
            </div>
          ) : (
            <div className="flex flex-col lg:flex-row gap-8 items-start animate-in fade-in slide-in-from-bottom-4 duration-500">
              {/* Layout Sidebar - No Print */}
              <div className="no-print w-full lg:w-80 bg-white border rounded-2xl p-6 space-y-6">
                <div className="flex items-center justify-between">
                  <h3 className="font-bold text-gray-800 flex items-center space-x-2">
                    <Settings size={18} />
                    <span>Cấu hình in</span>
                  </h3>
                  <button 
                    onClick={() => setIsEditingLayout(!isEditingLayout)}
                    className={`px-3 py-1 rounded-full text-xs font-medium transition-colors ${
                      isEditingLayout ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    {isEditingLayout ? 'Lưu vị trí' : 'Kéo thả'}
                  </button>
                </div>

                <div className="space-y-4">
                  <p className="text-xs text-gray-500 italic">Chọn các trường thông tin hiển thị trên giấy A4:</p>
                  <div className="space-y-2 max-h-[50vh] overflow-y-auto pr-2">
                    {elements.map((el) => (
                      <div key={el.id} className="flex items-center justify-between p-2 rounded-lg hover:bg-gray-50 border border-transparent hover:border-gray-100 transition-all">
                        <div className="flex items-center space-x-3">
                          <input 
                            type="checkbox" 
                            checked={el.isVisible} 
                            onChange={(e) => updateElement(el.id, { isVisible: e.target.checked })}
                            className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                          />
                          <span className="text-sm font-medium text-gray-700">{el.label}</span>
                        </div>
                        {isEditingLayout && (
                          <div className="flex items-center space-x-2">
                             <input 
                               type="number" 
                               value={el.fontSize} 
                               onChange={(e) => updateElement(el.id, { fontSize: parseInt(e.target.value) || 12 })}
                               className="w-12 text-center text-[10px] border rounded py-1"
                             />
                          </div>
                        )}
                      </div>
                    ))}
                  </div>

                  <button 
                    onClick={resetLayout}
                    className="w-full py-2 text-xs font-medium text-gray-500 hover:text-blue-600 hover:bg-blue-50 border rounded-lg transition-colors border-dashed"
                  >
                    Khôi phục mặc định
                  </button>
                </div>
              </div>

              {/* A4 Canvas */}
              <div className="flex-1 w-full flex justify-center">
                <div 
                  ref={containerRef}
                  className="print-area bg-white shadow-2xl overflow-hidden relative"
                  style={{
                    width: '210mm',
                    height: '297mm',
                    minWidth: '210mm',
                    transform: 'scale(1)', // Can be adjusted for view scale
                    transformOrigin: 'top center'
                  }}
                >
                  {/* Decorative background for layout - No Print */}
                  <div className="no-print absolute inset-0 opacity-10 pointer-events-none">
                    <div className="grid grid-cols-12 h-full w-full">
                       {[...Array(12)].map((_, i) => <div key={i} className="border-r border-gray-300" />)}
                    </div>
                  </div>

                  {elements.map((el) => (
                    <DraggableItem
                      key={el.id}
                      element={el}
                      value={data[el.key]}
                      onUpdate={updateElement}
                      containerRef={containerRef}
                      isEditing={isEditingLayout}
                    />
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer - No Print */}
      <footer className="no-print bg-white border-t p-4">
        <div className="max-w-7xl mx-auto flex justify-between items-center text-gray-400 text-xs">
          <p>© 2024 InsureExtract AI. Hỗ trợ tất cả mẫu bảo hiểm ô tô/xe máy.</p>
          <div className="flex space-x-4">
            <span className="flex items-center space-x-1">
               <div className="w-2 h-2 rounded-full bg-green-500"></div>
               <span>AI Engine Ready</span>
            </span>
            <span className="flex items-center space-x-1">
               <div className="w-2 h-2 rounded-full bg-blue-500"></div>
               <span>Secure Data</span>
            </span>
          </div>
        </div>
      </footer>
    </div>
  );
};

