import React, { useState, useRef, useEffect } from 'react';
import { QRCodeSVG } from 'qrcode.react';
import { PrintableElement } from '../types';

interface DraggableItemProps {
  element: PrintableElement;
  value: string;
  onUpdate: (id: string, updates: Partial<PrintableElement>) => void;
  containerRef: React.RefObject<HTMLDivElement>;
  isEditing: boolean;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ 
  element, 
  value, 
  onUpdate, 
  containerRef,
  isEditing
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragRef = useRef<{ startX: number; startY: number; initialX: number; initialY: number } | null>(null);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!isEditing) return;
    setIsDragging(true);
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      initialX: element.x,
      initialY: element.y
    };
    e.preventDefault();
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging || !dragRef.current || !containerRef.current) return;

      const deltaX = e.clientX - dragRef.current.startX;
      const deltaY = e.clientY - dragRef.current.startY;

      const containerRect = containerRef.current.getBoundingClientRect();

      let newX = dragRef.current.initialX + deltaX;
      let newY = dragRef.current.initialY + deltaY;

      // Giới hạn trong vùng chứa
      newX = Math.max(0, Math.min(newX, containerRect.width - 20));
      newY = Math.max(0, Math.min(newY, containerRect.height - 20));

      onUpdate(element.id, { x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, onUpdate, element.id, containerRef]);

  if (!element.isVisible) return null;

  return (
    <div
      style={{
        position: 'absolute',
        left: `${element.x}px`,
        top: `${element.y}px`,
        fontSize: `${element.fontSize}px`,
        fontWeight: element.fontWeight,
        cursor: isEditing ? 'move' : 'default',
        userSelect: 'none',
        zIndex: isDragging ? 50 : 10,
        backgroundColor: isDragging ? 'rgba(16, 185, 129, 0.1)' : 'transparent',
        border: isEditing ? '1px dashed #10b981' : 'none',
        padding: isEditing ? '4px' : '0',
        whiteSpace: 'nowrap'
      }}
      onMouseDown={handleMouseDown}
      className="transition-colors duration-150"
    >
      {element.key === 'qrCode' ? (
        value ? (
          <div className="bg-white p-2 inline-block shadow-sm border border-gray-100">
             <QRCodeSVG value={value} size={110} level="H" includeMargin={true} />
          </div>
        ) : (
          isEditing && (
            <div className="w-28 h-28 bg-emerald-50 border-2 border-emerald-200 border-dashed flex flex-col items-center justify-center text-[10px] text-emerald-600 font-bold">
              <span>MÃ QR</span>
              <span className="opacity-50">(Chưa có dữ liệu)</span>
            </div>
          )
        )
      ) : (
        <span>{value || (isEditing ? `[${element.label}]` : '')}</span>
      )}
    </div>
  );
};

import React, { useState, useCallback, useRef, useMemo } from 'react';
import { 
  FileText, 
  Printer, 
  Layout, 
  List, 
  Upload, 
  Settings,
  AlertCircle,
  Loader2,
  Edit3,
} from 'lucide-react';
import { InsuranceData, PrintableElement, TabType } from './types';
import { DEFAULT_ELEMENTS, EMPTY_INSURANCE } from './constants';
import { extractInsuranceData } from './services/geminiService';
import { DraggableItem } from './components/DraggableItem';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('list');
  const [data, setData] = useState<InsuranceData>(EMPTY_INSURANCE);
  const [elements, setElements] = useState<PrintableElement[]>(DEFAULT_ELEMENTS);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isEditingLayout, setIsEditingLayout] = useState(false);
  const [pdfLink, setPdfLink] = useState('');

  const containerRef = useRef<HTMLDivElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        try {
          const result = await extractInsuranceData(base64, file.type);
          setData(result);
        } catch (err: any) {
          setError(err.message || "Không thể trích xuất dữ liệu");
        } finally {
          setIsLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Lỗi đọc file");
      setIsLoading(false);
    }
  };

  const handleUrlUpload = async () => {
    if (!pdfLink) return;
    setIsLoading(true);
    setError(null);
    try {
      const response = await fetch(pdfLink);
      const blob = await response.blob();
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        const result = await extractInsuranceData(base64, blob.type);
        setData(result);
        setIsLoading(false);
      };
      reader.readAsDataURL(blob);
    } catch (err) {
      setError("Không thể tải trực tiếp link này. Hãy tải file PDF về máy và dùng nút 'Tải PDF'.");
      setIsLoading(false);
    }
  };

  const updateElement = useCallback((id: string, updates: Partial<PrintableElement>) => {
    setElements(prev => prev.map(el => el.id === id ? { ...el, ...updates } : el));
  }, []);

  const handlePrint = () => {
    window.print();
  };

  const handleDataChange = (key: keyof InsuranceData, value: string) => {
    setData(prev => ({ ...prev, [key]: value }));
  };

  const resetLayout = () => {
    setElements(DEFAULT_ELEMENTS);
  };

  // Logic QR: Ưu tiên QR từ PDF, nếu không có thì dùng chính link input làm QR
  const finalQrValue = useMemo(() => {
    return data.qrCode || pdfLink || '';
  }, [data.qrCode, pdfLink]);

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header - Không in */}
      <header className="no-print bg-white border-b sticky top-0 z-50 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="bg-emerald-600 p-2 rounded-lg text-white">
              <FileText size={24} />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-gray-800">InsureExtract <span className="text-xs font-normal text-gray-400">v2.1</span></h1>
          </div>

          <div className="flex-1 max-w-xl mx-8">
            <div className="relative group">
              <input
                type="text"
                placeholder="Nhập link PDF bảo hiểm..."
                className="w-full pl-4 pr-24 py-2 bg-gray-100 border-none rounded-full focus:ring-2 focus:ring-emerald-500 transition-all text-sm outline-none"
                value={pdfLink}
                onChange={(e) => setPdfLink(e.target.value)}
              />
              <button 
                onClick={handleUrlUpload}
                disabled={isLoading}
                className="absolute right-1 top-1 bottom-1 px-4 bg-emerald-600 text-white rounded-full text-xs font-medium hover:bg-emerald-700 disabled:opacity-50 transition-colors"
              >
                {isLoading ? <Loader2 className="animate-spin" size={16} /> : 'Đọc Link'}
              </button>
            </div>
          </div>

          <div className="flex items-center space-x-3">
            <label className="flex items-center space-x-2 px-4 py-2 bg-gray-100 hover:bg-gray-200 rounded-lg cursor-pointer transition-colors text-sm font-medium">
              <Upload size={18} className="text-gray-600" />
              <span>Tải PDF</span>
              <input type="file" className="hidden" accept="application/pdf,image/*" onChange={handleFileUpload} />
            </label>
            <button 
              onClick={handlePrint}
              className="flex items-center space-x-2 px-4 py-2 bg-emerald-600 text-white hover:bg-emerald-700 rounded-lg transition-all text-sm font-medium shadow-md shadow-emerald-100"
            >
              <Printer size={18} />
              <span>In Ngang A4</span>
            </button>
          </div>
        </div>
      </header>

      {/* Điều hướng Tab - Không in */}
      <div className="no-print bg-white border-b sticky top-16 z-40">
        <div className="max-w-7xl mx-auto px-4">
          <nav className="flex space-x-8">
