import { GoogleGenAI, Type } from "@google/genai";
import { InsuranceData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const extractInsuranceData = async (fileBase64: string, mimeType: string): Promise<InsuranceData> => {
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model: model,
    contents: [
      {
        parts: [
          {
            text: `Phân tích tài liệu bảo hiểm xe cơ giới này và trích xuất thông tin vào JSON. 
            Yêu cầu đặc biệt:
            1. Thời hạn bảo hiểm (ví dụ: "từ 10:00 ngày 01/01/2024 đến 10:00 ngày 01/01/2025"):
               - Tách thành startHour (10:00), startDate (01/01/2024), endHour (10:00), endDate (01/01/2025).
            2. Bảo hiểm tai nạn lái phụ xe & người ngồi trên xe:
               - Trích xuất accidentSeats (số chỗ), accidentAmount (mức tiền bảo hiểm/người), accidentFee (phí bảo hiểm tai nạn).
            3. QR Code: trích xuất chuỗi ký tự nếu có.

            Các trường cần: qrCode, serialNumber, ownerName, address, licensePlate, chassisNumber, engineNumber, vehicleType, weight, seats, purpose, startHour, startDate, endHour, endDate, fee, accidentSeats, accidentAmount, accidentFee, totalFee.`
          },
          {
            inlineData: {
              data: fileBase64,
              mimeType: mimeType
            }
          }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          qrCode: { type: Type.STRING },
          serialNumber: { type: Type.STRING },
          ownerName: { type: Type.STRING },
          address: { type: Type.STRING },
          licensePlate: { type: Type.STRING },
          chassisNumber: { type: Type.STRING },
          engineNumber: { type: Type.STRING },
          vehicleType: { type: Type.STRING },
          weight: { type: Type.STRING },
          seats: { type: Type.STRING },
          purpose: { type: Type.STRING },
          startHour: { type: Type.STRING },
          startDate: { type: Type.STRING },
          endHour: { type: Type.STRING },
          endDate: { type: Type.STRING },
          fee: { type: Type.STRING },
          accidentSeats: { type: Type.STRING },
          accidentAmount: { type: Type.STRING },
          accidentFee: { type: Type.STRING },
          totalFee: { type: Type.STRING },
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}') as InsuranceData;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Không thể xử lý dữ liệu từ Gemini");
  }
};

