import { GoogleGenAI, Type } from "@google/genai";
import { InsuranceData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const extractInsuranceData = async (fileBase64: string, mimeType: string): Promise<InsuranceData> => {
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model: model,
    contents: [
      {
        parts: [
          {
            text: `Hãy phân tích tài liệu bảo hiểm xe cơ giới này và trích xuất thông tin vào JSON theo các quy tắc sau:
            1. Thời hạn bảo hiểm: Tìm chuỗi có dạng "từ... đến...". Tách thành 4 trường: startHour (ví dụ 10:00), startDate (01/01/2024), endHour (10:00), endDate (01/01/2025).
            2. Bảo hiểm tai nạn lái phụ xe & người ngồi trên xe: Tìm thông tin về số chỗ ngồi (accidentSeats), mức tiền bảo hiểm/người (accidentAmount) và phí bảo hiểm tai nạn (accidentFee).
            3. QR Code: Nếu thấy mã QR, trích xuất chuỗi ký tự bên trong.
            4. Các thông số xe: serialNumber, ownerName, address, licensePlate, chassisNumber, engineNumber, vehicleType, weight, seats, purpose, fee (phí TNDS).
            Dữ liệu trả về chỉ gồm JSON.`
          },
          {
            inlineData: {
              data: fileBase64,
              mimeType: mimeType
            }
          }
        ]
      }
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          qrCode: { type: Type.STRING },
          serialNumber: { type: Type.STRING },
          ownerName: { type: Type.STRING },
          address: { type: Type.STRING },
          licensePlate: { type: Type.STRING },
          chassisNumber: { type: Type.STRING },
          engineNumber: { type: Type.STRING },
          vehicleType: { type: Type.STRING },
          weight: { type: Type.STRING },
          seats: { type: Type.STRING },
          purpose: { type: Type.STRING },
          startHour: { type: Type.STRING },
          startDate: { type: Type.STRING },
          endHour: { type: Type.STRING },
          endDate: { type: Type.STRING },
          fee: { type: Type.STRING },
          accidentSeats: { type: Type.STRING },
          accidentAmount: { type: Type.STRING },
          accidentFee: { type: Type.STRING },
        }
      }
    }
  });

  try {
    const text = response.text || '{}';
    return JSON.parse(text) as InsuranceData;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Không thể xử lý dữ liệu từ Gemini. Vui lòng thử lại.");
  }
};

