import React, { useState, useRef, useEffect } from 'react';
import { QRCodeSVG } from 'qrcode.react';
import { PrintableElement } from '../types';

interface DraggableItemProps {
  element: PrintableElement;
  value: string;
  onUpdate: (id: string, updates: Partial<PrintableElement>) => void;
  containerRef: React.RefObject<HTMLDivElement>;
  isEditing: boolean;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ 
  element, 
  value, 
  onUpdate, 
  containerRef,
  isEditing
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragRef = useRef<{ startX: number; startY: number; initialX: number; initialY: number } | null>(null);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!isEditing) return;
    setIsDragging(true);
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      initialX: element.x,
      initialY: element.y
    };
    e.preventDefault();
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging || !dragRef.current || !containerRef.current) return;

      const deltaX = e.clientX - dragRef.current.startX;
      const deltaY = e.clientY - dragRef.current.startY;

      const containerRect = containerRef.current.getBoundingClientRect();

      let newX = dragRef.current.initialX + deltaX;
      let newY = dragRef.current.initialY + deltaY;

      // Giới hạn trong vùng chứa
      newX = Math.round(Math.max(0, Math.min(newX, containerRect.width - 20)));
      newY = Math.round(Math.max(0, Math.min(newY, containerRect.height - 20)));

      onUpdate(element.id, { x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, onUpdate, element.id, containerRef]);

  // Logic hiển thị phần tử đặc biệt "Dòng gạch chéo"
  // Chỉ hiển thị trên bản in nếu phí = 0, nhưng luôn hiển thị trong chế độ sửa để kéo thả
  const isStrikeLine = element.id === 'strikeLine';
  const shouldShowStrike = isStrikeLine && (value === '0' || isEditing);

  if (!element.isVisible || (isStrikeLine && !shouldShowStrike)) return null;

  return (
    <div
      style={{
        position: 'absolute',
        left: `${element.x}px`,
        top: `${element.y}px`,
        fontSize: isStrikeLine ? '0' : `${element.fontSize}px`,
        fontWeight: element.fontWeight,
        cursor: isEditing ? 'move' : 'default',
        userSelect: 'none',
        zIndex: isDragging ? 50 : 10,
        backgroundColor: isDragging ? 'rgba(16, 185, 129, 0.1)' : 'transparent',
        border: isEditing ? '1px dashed #10b981' : 'none',
        padding: isEditing ? '4px' : '0',
        whiteSpace: 'nowrap'
      }}
      onMouseDown={handleMouseDown}
      className="transition-colors duration-150"
    >
      {/* Hiển thị tọa độ khi đang sửa */}
      {isEditing && (
        <div className="absolute -top-6 left-0 bg-gray-800 text-white text-[9px] px-1.5 py-0.5 rounded font-mono z-[100] whitespace-nowrap shadow-sm opacity-80 pointer-events-none no-print">
          X:{element.x}, Y:{element.y}
        </div>
      )}

      {isStrikeLine ? (
        <div className="relative w-[150px] h-[300px] border-l-2 border-gray-400 opacity-60" style={{ transform: 'rotate(65deg)', transformOrigin: 'top left' }}>
           {/* Dòng kẻ chéo */}
           <div className="absolute top-0 left-0 w-full h-[2px] bg-black"></div>
        </div>
      ) : element.key === 'qrCode' ? (
        value ? (
          <div className="bg-white p-2 inline-block shadow-sm border border-gray-100">
             <QRCodeSVG value={value} size={110} level="H" includeMargin={true} />
          </div>
        ) : (
          isEditing && (
            <div className="w-28 h-28 bg-emerald-50 border-2 border-emerald-200 border-dashed flex flex-col items-center justify-center text-[10px] text-emerald-600 font-bold">
              <span>MÃ QR</span>
              <span className="opacity-50">(Chưa có dữ liệu)</span>
            </div>
          )
        )
      ) : (
        <span>{value || (isEditing ? `[${element.label}]` : '')}</span>
      )}
    </div>
  );
};

