          serialNumber: { type: Type.STRING },
          ownerName: { type: Type.STRING },
          address: { type: Type.STRING },
          licensePlate: { type: Type.STRING },
          chassisNumber: { type: Type.STRING },
          engineNumber: { type: Type.STRING },
          vehicleType: { type: Type.STRING },
          weight: { type: Type.STRING },
          seats: { type: Type.STRING },
          purpose: { type: Type.STRING },
          startHour: { type: Type.STRING },
          startDay: { type: Type.STRING },
          startMonth: { type: Type.STRING },
          startYear: { type: Type.STRING },
          endHour: { type: Type.STRING },
          endDay: { type: Type.STRING },
          endMonth: { type: Type.STRING },
          endYear: { type: Type.STRING },
          fee: { type: Type.STRING },
          accidentSeats: { type: Type.STRING },
          accidentAmount: { type: Type.STRING },
          accidentFee: { type: Type.STRING },
        }
      }
    }
  });

  try {
    const text = response.text || '{}';
    return JSON.parse(text) as InsuranceData;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Không thể xử lý dữ liệu từ Gemini. Vui lòng thử lại.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { QRCodeSVG } from 'qrcode.react';
import { PrintableElement } from '../types';

interface DraggableItemProps {
  element: PrintableElement;
  value: string;
  onUpdate: (id: string, updates: Partial<PrintableElement>) => void;
  containerRef: React.RefObject<HTMLDivElement>;
  isEditing: boolean;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ 
  element, 
  value, 
  onUpdate, 
  containerRef,
  isEditing
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragRef = useRef<{ startX: number; startY: number; initialX: number; initialY: number } | null>(null);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!isEditing) return;
    setIsDragging(true);
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      initialX: element.x,
      initialY: element.y
    };
    e.preventDefault();
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging || !dragRef.current || !containerRef.current) return;

      const deltaX = e.clientX - dragRef.current.startX;
      const deltaY = e.clientY - dragRef.current.startY;

      const containerRect = containerRef.current.getBoundingClientRect();

      let newX = dragRef.current.initialX + deltaX;
      let newY = dragRef.current.initialY + deltaY;

      // Giới hạn trong vùng chứa
      newX = Math.round(Math.max(0, Math.min(newX, containerRect.width - 20)));
      newY = Math.round(Math.max(0, Math.min(newY, containerRect.height - 20)));

      onUpdate(element.id, { x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, onUpdate, element.id, containerRef]);

  const isStrikeLine = element.id === 'strikeLine';
  // Luôn hiện gạch chéo trong mode edit để dễ kéo, hoặc khi phí TN = 0
  const shouldShowStrike = isStrikeLine && (value === '0' || isEditing);

  if (!element.isVisible || (isStrikeLine && !shouldShowStrike)) return null;

  return (
    <div
      style={{
        position: 'absolute',
        left: `${element.x}px`,
        top: `${element.y}px`,
        fontSize: isStrikeLine ? '0' : `${element.fontSize}px`,
        fontWeight: element.fontWeight,
        cursor: isEditing ? 'move' : 'default',
        userSelect: 'none',
        zIndex: isDragging ? 50 : 10,
        backgroundColor: isDragging ? 'rgba(16, 185, 129, 0.1)' : 'transparent',
        border: isEditing && !isStrikeLine ? '1px dashed #10b981' : 'none',
        padding: isEditing && !isStrikeLine ? '4px' : '0',
        whiteSpace: 'nowrap'
      }}
      onMouseDown={handleMouseDown}
      className="transition-colors duration-150"
    >
      {isEditing && (
        <div className="absolute -top-6 left-0 bg-gray-800 text-white text-[9px] px-1.5 py-0.5 rounded font-mono z-[100] whitespace-nowrap shadow-sm opacity-80 pointer-events-none no-print">
          X:{element.x}, Y:{element.y}
        </div>
      )}

      {isStrikeLine ? (
        <div style={{ position: 'relative', width: '20px', height: '20px' }}>
          {/* 
              Vẽ một đường line từ (element.x, element.y) - điểm neo
              Theo yêu cầu: Gạch dài từ 280:240 đến 160:480.
              Khoảng cách X = -120, Y = +240.
          */}
          <svg 
            width="300" 
            height="300" 
            style={{ 
              position: 'absolute', 
              top: 0, 
              left: 0, 
              overflow: 'visible',
              pointerEvents: 'none'
            }}
          >
            <line 
              x1="0" 
              y1="0" 
              x2="-120" 
              y2="240" 
              stroke="gray" 
              strokeWidth="2" 
              strokeDasharray={isEditing ? "4 4" : "0"}
            />
          </svg>
          {isEditing && (
             <div className="w-4 h-4 rounded-full bg-emerald-500 border-2 border-white shadow-sm absolute -translate-x-1/2 -translate-y-1/2 no-print" />
          )}
        </div>
      ) : element.key === 'qrCode' ? (
        value ? (
          <div className="bg-white p-2 inline-block shadow-sm border border-gray-100">
             <QRCodeSVG value={value} size={110} level="H" includeMargin={true} />
          </div>
        ) : (
          isEditing && (
            <div className="w-28 h-28 bg-emerald-50 border-2 border-emerald-200 border-dashed flex flex-col items-center justify-center text-[10px] text-emerald-600 font-bold">
              <span>MÃ QR</span>
            </div>
          )
        )
      ) : (
        <span>{value || (isEditing ? `[${element.label}]` : '')}</span>
      )}
    </div>
  );
};

