  key: keyof InsuranceData;
  label: string;
  x: number;
  y: number;
  fontSize: number;
  size?: number; // Dành cho mã QR hoặc các phần tử cần kích thước riêng
  fontWeight: string;
  isVisible: boolean;
}

export type TabType = 'list' | 'print';

import React, { useState, useRef, useEffect } from 'react';
import { QRCodeSVG } from 'qrcode.react';
import { PrintableElement } from '../types';

interface DraggableItemProps {
  element: PrintableElement;
  value: string;
  onUpdate: (id: string, updates: Partial<PrintableElement>) => void;
  containerRef: React.RefObject<HTMLDivElement>;
  isEditing: boolean;
  isSelected: boolean;
  onSelect: (id: string, multi: boolean) => void;
}

export const DraggableItem: React.FC<DraggableItemProps> = ({ 
  element, 
  value, 
  onUpdate, 
  containerRef,
  isEditing,
  isSelected,
  onSelect
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const dragRef = useRef<{ startX: number; startY: number; initialX: number; initialY: number } | null>(null);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!isEditing) return;
    onSelect(element.id, e.shiftKey || e.ctrlKey || e.metaKey);
    setIsDragging(true);
    dragRef.current = {
      startX: e.clientX,
      startY: e.clientY,
      initialX: element.x,
      initialY: element.y
    };
    e.preventDefault();
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging || !dragRef.current || !containerRef.current) return;

      const deltaX = e.clientX - dragRef.current.startX;
      const deltaY = e.clientY - dragRef.current.startY;

      const containerRect = containerRef.current.getBoundingClientRect();

      let newX = dragRef.current.initialX + deltaX;
      let newY = dragRef.current.initialY + deltaY;

      newX = Math.round(Math.max(0, Math.min(newX, containerRect.width - 20)));
      newY = Math.round(Math.max(0, Math.min(newY, containerRect.height - 20)));

      onUpdate(element.id, { x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, onUpdate, element.id, containerRef]);

  // Logic định dạng hiển thị đặc biệt
  const getDisplayValue = () => {
    if (!value) return isEditing ? `[${element.label}]` : '';

    // Số tiền bảo hiểm lái phụ xe: lấy giá trị triệu (chia 1.000.000)
    if (element.key === 'accidentAmount') {
      const num = parseInt(value.replace(/\D/g, ''));
      if (!isNaN(num) && num >= 1000000) {
        return Math.floor(num / 1000000).toString();
      }
      return value;
    }

    // Năm cấp: chỉ lấy 2 số cuối
    if (element.key === 'issueYear') {
      return value.length > 2 ? value.slice(-2) : value;
    }

    return value;
  };

  const isStrikeLine = element.id === 'strikeLine';
  const shouldShowStrike = isStrikeLine && (value === '0' || isEditing);

  if (!element.isVisible || (isStrikeLine && !shouldShowStrike)) return null;

  const displayValue = getDisplayValue();

  return (
    <div
      style={{
        position: 'absolute',
        left: `${element.x}px`,
        top: `${element.y}px`,
        fontSize: isStrikeLine ? '0' : `${element.fontSize}px`,
        fontWeight: element.fontWeight,
        cursor: isEditing ? 'move' : 'default',
        userSelect: 'none',
        zIndex: isDragging ? 50 : 10,
        backgroundColor: isDragging ? 'rgba(16, 185, 129, 0.1)' : 'transparent',
        border: isEditing && !isStrikeLine ? (isSelected ? '2px solid #10b981' : '1px dashed #10b981') : 'none',
        padding: isEditing && !isStrikeLine ? '4px' : '0',
        whiteSpace: 'nowrap',
        boxShadow: isSelected && isEditing ? '0 0 10px rgba(16, 185, 129, 0.3)' : 'none'
      }}
      onMouseDown={handleMouseDown}
      className="transition-all duration-150"
    >
      {isEditing && (
        <div className={`absolute -top-6 left-0 text-white text-[9px] px-1.5 py-0.5 rounded font-mono z-[100] whitespace-nowrap shadow-sm pointer-events-none no-print ${isSelected ? 'bg-emerald-600 font-bold opacity-100' : 'bg-gray-800 opacity-80'}`}>
          X:{element.x}, Y:{element.y}
        </div>
      )}

      {isStrikeLine ? (
        <div style={{ position: 'relative', width: '20px', height: '20px' }}>
          <svg 
            width="300" 
            height="300" 
            style={{ 
              position: 'absolute', 
              top: 0, 
              left: 0, 
              overflow: 'visible',
              pointerEvents: 'none'
            }}
          >
            <line 
              x1="0" 
              y1="0" 
              x2="-120" 
              y2="240" 
              stroke={isSelected ? "#10b981" : "gray"} 
              strokeWidth={isSelected ? "3" : "2"} 
              strokeDasharray={isEditing ? "4 4" : "0"}
            />
          </svg>
          {isEditing && (
             <div className={`w-4 h-4 rounded-full border-2 border-white shadow-sm absolute -translate-x-1/2 -translate-y-1/2 no-print ${isSelected ? 'bg-emerald-600 scale-125' : 'bg-emerald-500'}`} />
          )}
        </div>
      ) : element.key === 'qrCode' ? (
        value ? (
          <div className={`bg-white p-2 inline-block shadow-sm border ${isSelected ? 'border-emerald-500' : 'border-gray-100'}`}>
             <QRCodeSVG value={value} size={element.size || 110} level="H" includeMargin={true} />
          </div>
        ) : (
          isEditing && (
            <div 
              style={{ width: element.size || 110, height: element.size || 110 }}
              className={`bg-emerald-50 border-2 border-dashed flex flex-col items-center justify-center text-[10px] text-emerald-600 font-bold ${isSelected ? 'border-emerald-500' : 'border-emerald-200'}`}
            >
              <span>MÃ QR</span>
            </div>
          )
        )
      ) : (
        <span>{displayValue}</span>
      )}
    </div>
  );
};

import React, { useState, useCallback, useRef, useMemo, useEffect } from 'react';
import { 
  FileText, 
  Printer, 
  Layout, 
  List, 
  Upload, 
  Settings,
  AlertCircle,
  Loader2,
  Edit3,
  Calendar,
  Clock,
  MousePointer2,
  Type as TypeIcon,
  Maximize2
} from 'lucide-react';
import { InsuranceData, PrintableElement, TabType } from './types';
import { DEFAULT_ELEMENTS, EMPTY_INSURANCE, LABEL_MAP } from './constants';
import { extractInsuranceData } from './services/geminiService';
import { DraggableItem } from './components/DraggableItem';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('list');
  const [data, setData] = useState<InsuranceData>(EMPTY_INSURANCE);
  const [elements, setElements] = useState<PrintableElement[]>(DEFAULT_ELEMENTS);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isEditingLayout, setIsEditingLayout] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);

  const applyVehicleTypeLogic = (weightValue: string): string => {
    return weightValue && weightValue.trim() !== '' ? 'Xe tải' : 'Xe ô tô con';
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        try {
          const result = await extractInsuranceData(base64, file.type);
          result.vehicleType = applyVehicleTypeLogic(result.weight);
          setData(result);
        } catch (err: any) {
          setError(err.message || "Không thể trích xuất dữ liệu");
        } finally {
          setIsLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Lỗi khi đọc tệp tin.");
      setIsLoading(false);
    }
  };

  const updateElement = useCallback((id: string, updates: Partial<PrintableElement>) => {
    setElements(prev => prev.map(el => el.id === id ? { ...el, ...updates } : el));
  }, []);

  const handleSelect = useCallback((id: string, multi: boolean) => {
    setSelectedIds(prev => {
      if (multi) {
        return prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id];
      }
      return [id];
    });
  }, []);

  // Keyboard controls for layout
  useEffect(() => {
    if (!isEditingLayout || selectedIds.length === 0) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      const step = e.shiftKey ? 10 : 1;
      let dx = 0;
      let dy = 0;

      if (e.key === 'ArrowUp') dy = -step;
      else if (e.key === 'ArrowDown') dy = step;
      else if (e.key === 'ArrowLeft') dx = -step;
      else if (e.key === 'ArrowRight') dx = step;
      else if (e.key === 'Escape') {
        setSelectedIds([]);
        return;
      } else return;

      e.preventDefault();
      setElements(prev => prev.map(el => 
        selectedIds.includes(el.id) 
          ? { ...el, x: Math.max(0, el.x + dx), y: Math.max(0, el.y + dy) } 
          : el
      ));
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isEditingLayout, selectedIds]);

  const handlePrint = () => {
    window.print();
  };

  const handleDataChange = (key: keyof InsuranceData, value: string) => {
    setData(prev => {
      const newData = { ...prev, [key]: value };
      if (key === 'weight') newData.vehicleType = applyVehicleTypeLogic(value);
      return newData;
    });
  };

  const resetLayout = () => {
    setElements(DEFAULT_ELEMENTS);
    setSelectedIds([]);
  };

  const finalQrValue = useMemo(() => data.qrCode || '', [data.qrCode]);

  const renderInput = (key: keyof InsuranceData, placeholder = "...", customLabel?: string) => (
    <div className="flex flex-col space-y-1 w-full">
      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest ml-1">{customLabel || LABEL_MAP[key]}</label>
      <input
        type="text"
        value={data[key] || ''}
        onChange={(e) => handleDataChange(key, e.target.value)}
        className={`w-full px-4 py-2 border border-gray-100 rounded-xl focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all text-sm outline-none font-semibold ${key === 'qrCode' ? 'bg-emerald-50/50 border-emerald-100 italic text-emerald-700' : 'bg-gray-50/50'}`}
        placeholder={placeholder}
      />
    </div>
  );

  const selectedElements = elements.filter(el => selectedIds.includes(el.id));

  return (
    <div className="h-screen flex flex-col bg-gray-50 overflow-hidden relative">
      <header className="no-print bg-white border-b shrink-0 z-50">
        <div className="max-w-full mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-emerald-600 p-2 rounded-lg text-white">
              <FileText size={24} />
            </div>
            <div>
              <h1 className="text-lg font-bold text-gray-800 leading-tight">In Bảo Hiểm Tự Động</h1>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Hệ thống v4.1 • AI Extractor</p>
            </div>
          </div>
          <div className="flex items-center space-x-3">
            <label className="flex items-center space-x-2 px-4 py-2 bg-emerald-50 text-emerald-700 hover:bg-emerald-100 rounded-xl cursor-pointer transition-all text-sm font-bold border border-emerald-100">
              <Upload size={18} />
              <span>Tải tài liệu</span>
              <input type="file" className="hidden" accept="application/pdf,image/*" onChange={handleFileUpload} />
            </label>
            <button onClick={handlePrint} className="flex items-center space-x-2 px-5 py-2 bg-gray-800 text-white hover:bg-gray-900 rounded-xl transition-all text-sm font-bold shadow-lg shadow-gray-200 active:scale-95">
              <Printer size={18} />
              <span>In A4 Ngang</span>
            </button>
          </div>
        </div>
      </header>

      <nav className="no-print bg-white border-b shrink-0 px-6">
        <div className="flex space-x-8">
          {[
            { id: 'list', label: 'Trích xuất', icon: <List size={18} /> },
            { id: 'print', label: 'Bố cục bản in', icon: <Layout size={18} /> }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as TabType)}
              className={`py-4 px-2 border-b-2 font-bold text-sm flex items-center space-x-2 transition-all ${
                activeTab === tab.id ? 'border-emerald-600 text-emerald-600' : 'border-transparent text-gray-400 hover:text-gray-600'
              }`}
            >
              {tab.icon}
              <span>{tab.label}</span>
            </button>
          ))}
        </div>
      </nav>

      <main className="flex-1 overflow-hidden relative">
        {isLoading && (
          <div className="absolute inset-0 bg-white/80 backdrop-blur-sm z-[100] flex flex-col items-center justify-center text-center">
            <div className="bg-white p-8 rounded-3xl shadow-2xl flex flex-col items-center border border-emerald-50 scale-110">
              <Loader2 className="animate-spin text-emerald-600 mb-4" size={48} />
              <p className="text-lg font-bold text-gray-800">Đang trích xuất dữ liệu...</p>
            </div>
          </div>
        )}

        <div className="h-full w-full flex flex-col">
          {/* Tab: Trích xuất */}
          <div className={`flex-1 overflow-y-auto p-6 no-print ${activeTab === 'list' ? 'block' : 'hidden'} custom-scrollbar`}>
            <div className="max-w-5xl mx-auto bg-white rounded-3xl shadow-sm border border-gray-100 p-8 h-fit">
              <div className="flex items-center justify-between mb-8 pb-4 border-b">
                <h3 className="text-xl font-bold text-gray-800 flex items-center space-x-3">
                  <Edit3 size={24} className="text-emerald-600" />
                  <span>Sửa thông tin</span>
                </h3>
                <button onClick={() => setData(EMPTY_INSURANCE)} className="px-4 py-2 text-xs font-bold text-red-500 bg-red-50 hover:bg-red-100 rounded-xl transition-colors uppercase">Làm mới</button>
              </div>

              <div className="flex flex-col space-y-5">
                <div className="w-full">{renderInput('qrCode', 'Dữ liệu mã QR', 'QR CODE LINK')}</div>
                <div className="flex gap-4">
                  {renderInput('serialNumber')}
                  {renderInput('licensePlate')}
                </div>
                <div className="w-full">{renderInput('ownerName')}</div>
                <div className="w-full">{renderInput('address')}</div>
                <div className="flex gap-4">
                  {renderInput('chassisNumber')}
                  {renderInput('engineNumber')}
                </div>
                <div className="flex gap-4">
                  {renderInput('vehicleType')}
                  {renderInput('weight')}
                  {renderInput('seats', '...', 'Số chỗ ngồi')}
                </div>
                <div className="flex gap-4">
                  {renderInput('purpose')}
                  {renderInput('fee', '...', 'Phí TNDS (Tổng có VAT)')}
                </div>

                <div className="flex items-center gap-4 p-3 bg-emerald-50/20 rounded-xl border border-emerald-100/30">
                  <div className="flex items-center gap-2 w-28 shrink-0 font-bold text-emerald-700 text-[11px] uppercase tracking-wider">
                    <Clock size={14} /> <span>Bắt đầu:</span>
                  </div>
                  {renderInput('startHour', 'Giờ')}
                  {renderInput('startDay', 'Ngày')}
