    if (element.key === 'issueYear') {
      const yearStr = value.trim();
      return yearStr.length >= 1 ? yearStr.slice(-1) : yearStr;
    }

    // Năm BĐ/KT: chỉ lấy 2 số cuối
    if (element.key === 'startYear' || element.key === 'endYear') {
      const yearStr = value.trim();
      return yearStr.length >= 2 ? yearStr.slice(-2) : yearStr;
    }

    return value;
  };

  const isStrikeLine = element.id === 'strikeLine';
  const shouldShowStrike = isStrikeLine && (value === '0' || isEditing);

  if (!element.isVisible || (isStrikeLine && !shouldShowStrike)) return null;

  const displayValue = getDisplayValue();

  return (
    <div
      style={{
        position: 'absolute',
        left: `${element.x}px`,
        top: `${element.y}px`,
        fontSize: isStrikeLine ? '0' : `${element.fontSize}px`,
        fontWeight: 'bold', // Luôn in đậm theo yêu cầu
        cursor: isEditing ? 'move' : 'default',
        userSelect: 'none',
        zIndex: isDragging ? 50 : 10,
        backgroundColor: isDragging ? 'rgba(16, 185, 129, 0.1)' : 'transparent',
        border: isEditing && !isStrikeLine ? (isSelected ? '2px solid #10b981' : '1px dashed #10b981') : 'none',
        padding: isEditing && !isStrikeLine ? '4px' : '0',
        // Cho phép địa chỉ hoặc nhãn tùy chỉnh xuống dòng
        whiteSpace: (element.key === 'address' || element.isCustom) ? 'normal' : 'nowrap',
        maxWidth: (element.key === 'address' || element.isCustom) ? '400px' : 'none',
        boxShadow: isSelected && isEditing ? '0 0 10px rgba(16, 185, 129, 0.3)' : 'none',
        lineHeight: '1.2'
      }}
      onMouseDown={handleMouseDown}
      className="transition-all duration-150"
    >
      {isEditing && (
        <div className={`absolute -top-6 left-0 text-white text-[9px] px-1.5 py-0.5 rounded font-mono z-[100] whitespace-nowrap shadow-sm pointer-events-none no-print ${isSelected ? 'bg-emerald-600 font-bold opacity-100' : 'bg-gray-800 opacity-80'}`}>
          X:{element.x}, Y:{element.y}
        </div>
      )}

      {isStrikeLine ? (
        <div style={{ position: 'relative', width: '20px', height: '20px' }}>
          <svg 
            width="300" 
            height="300" 
            style={{ 
              position: 'absolute', 
              top: 0, 
              left: 0, 
              overflow: 'visible',
              pointerEvents: 'none'
            }}
          >
            <line 
              x1="0" 
              y1="0" 
              x2="-120" 
              y2="240" 
              stroke={isSelected ? "#10b981" : "gray"} 
              strokeWidth={isSelected ? "3" : "2"} 
              strokeDasharray={isEditing ? "4 4" : "0"}
            />
          </svg>
          {isEditing && (
             <div className={`w-4 h-4 rounded-full border-2 border-white shadow-sm absolute -translate-x-1/2 -translate-y-1/2 no-print ${isSelected ? 'bg-emerald-600 scale-125' : 'bg-emerald-500'}`} />
          )}
        </div>
      ) : element.key === 'qrCode' ? (
        value ? (
          <div className={`bg-white p-2 inline-block shadow-sm border ${isSelected ? 'border-emerald-500' : 'border-gray-100'}`}>
             <QRCodeSVG value={value} size={element.size || 80} level="H" includeMargin={true} />
          </div>
        ) : (
          isEditing && (
            <div 
              style={{ width: element.size || 80, height: element.size || 80 }}
              className={`bg-emerald-50 border-2 border-dashed flex flex-col items-center justify-center text-[10px] text-emerald-600 font-bold ${isSelected ? 'border-emerald-500' : 'border-emerald-200'}`}
            >
              <span>MÃ QR</span>
            </div>
          )
        )
      ) : (
        <span style={{ display: 'block' }}>{displayValue}</span>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";

// File này chạy trên môi trường Server (Node.js) của Vercel/Netlify
// API_KEY được lấy trực tiếp từ Environment Variables của Server, không bao giờ lộ ra ngoài.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const { fileBase64, mimeType } = req.body;

  if (!fileBase64 || !mimeType) {
    return res.status(400).json({ error: 'Missing file data' });
  }

  try {
    const model = "gemini-3-flash-preview";

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        {
          parts: [
            {
              text: `Hãy phân tích tài liệu bảo hiểm xe cơ giới này và trích xuất thông tin vào JSON:
              1. Thời hạn: startHour, startMinute (phút), startDay, startMonth, startYear, endHour, endMinute (phút), endDay, endMonth, endYear.
              2. Phí TNDS (fee): TRÍCH XUẤT TỔNG PHÍ CUỐI CÙNG (đã bao gồm thuế GTGT/VAT 10%). Tìm giá trị lớn nhất trong phần phí TNDS hoặc dòng ghi "Tổng cộng tiền phí".
              3. Ngày cấp (Issue Date): Trích xuất ngày, tháng, năm cấp bảo hiểm (issueDay, issueMonth, issueYear).
              4. Tai nạn lái phụ xe: accidentSeats, accidentAmount, accidentFee.
              5. Xe: serialNumber, ownerName, address, licensePlate, chassisNumber, engineNumber, vehicleType, weight, seats, purpose.
              6. QR Code: Nội dung chuỗi QR.
              Chỉ trả về JSON hợp lệ, không chứa văn bản thừa.`
            },
            {
              inlineData: {
                data: fileBase64,
                mimeType: mimeType
              }
            }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            qrCode: { type: Type.STRING },
            serialNumber: { type: Type.STRING },
            ownerName: { type: Type.STRING },
            address: { type: Type.STRING },
            licensePlate: { type: Type.STRING },
            chassisNumber: { type: Type.STRING },
            engineNumber: { type: Type.STRING },
            vehicleType: { type: Type.STRING },
            weight: { type: Type.STRING },
            seats: { type: Type.STRING },
            purpose: { type: Type.STRING },
            startHour: { type: Type.STRING },
            startMinute: { type: Type.STRING },
            startDay: { type: Type.STRING },
            startMonth: { type: Type.STRING },
            startYear: { type: Type.STRING },
            endHour: { type: Type.STRING },
            endMinute: { type: Type.STRING },
            endDay: { type: Type.STRING },
            endMonth: { type: Type.STRING },
            endYear: { type: Type.STRING },
            fee: { type: Type.STRING },
            issueDay: { type: Type.STRING },
            issueMonth: { type: Type.STRING },
            issueYear: { type: Type.STRING },
            accidentSeats: { type: Type.STRING },
            accidentAmount: { type: Type.STRING },
            accidentFee: { type: Type.STRING },
          }
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return res.status(200).json(result);
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return res.status(500).json({ error: "Lỗi xử lý dữ liệu từ AI." });
  }
}

import { InsuranceData } from "../types";

/**
 * Service này giờ đây hoạt động như một Proxy Client.
 * Nó không cần API Key, không cần thư viện @google/genai ở frontend.
 * Nó chỉ gửi yêu cầu tới Backend (Serverless Function) của chính ứng dụng.
 */
export const extractInsuranceData = async (fileBase64: string, mimeType: string): Promise<InsuranceData> => {
  try {
    const response = await fetch('/api/extract', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ fileBase64, mimeType }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error || "Lỗi máy chủ proxy");
    }

    return await response.json() as InsuranceData;
  } catch (e: any) {
    console.error("Frontend Proxy Error:", e);
    throw new Error(e.message || "Không thể kết nối với dịch vụ trích xuất.");
  }
};

