import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  const { fileBase64, mimeType, url } = req.body;
  let finalBase64 = fileBase64;
  let finalMimeType = mimeType;

  try {
    // Nếu người dùng gửi URL, server sẽ tự tải file về
    if (url && !fileBase64) {
      console.log("Fetching remote PDF:", url);
      const response = await fetch(url);
      if (!response.ok) throw new Error("Không thể tải file từ link cung cấp.");

      const arrayBuffer = await response.arrayBuffer();
      finalBase64 = Buffer.from(arrayBuffer).toString('base64');
      finalMimeType = response.headers.get('content-type') || 'application/pdf';
    }

    if (!finalBase64) {
      return res.status(400).json({ error: 'Thiếu dữ liệu file hoặc URL' });
    }

    const model = "gemini-3-flash-preview";

    const geminiResponse = await ai.models.generateContent({
      model: model,
      contents: [
        {
          parts: [
            {
              text: `Hãy phân tích tài liệu bảo hiểm xe cơ giới này và trích xuất thông tin vào JSON:
              1. Thời hạn: startHour, startMinute (phút), startDay, startMonth, startYear, endHour, endMinute (phút), endDay, endMonth, endYear.
              2. Phí TNDS (fee): TRÍCH XUẤT TỔNG PHÍ CUỐI CÙNG (đã bao gồm thuế GTGT/VAT 10%). Tìm giá trị lớn nhất trong phần phí TNDS hoặc dòng ghi "Tổng cộng tiền phí".
              3. Ngày cấp (Issue Date): Trích xuất ngày, tháng, năm cấp bảo hiểm (issueDay, issueMonth, issueYear).
              4. Tai nạn lái phụ xe: accidentSeats, accidentAmount, accidentFee.
              5. Xe: serialNumber, ownerName, address, licensePlate, chassisNumber, engineNumber, vehicleType, weight, seats, purpose.
              6. QR Code: Nội dung chuỗi QR.
              Chỉ trả về JSON hợp lệ, không chứa văn bản thừa.`
            },
            {
              inlineData: {
                data: finalBase64,
                mimeType: finalMimeType
              }
            }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            qrCode: { type: Type.STRING },
            serialNumber: { type: Type.STRING },
            ownerName: { type: Type.STRING },
            address: { type: Type.STRING },
            licensePlate: { type: Type.STRING },
            chassisNumber: { type: Type.STRING },
            engineNumber: { type: Type.STRING },
            vehicleType: { type: Type.STRING },
            weight: { type: Type.STRING },
            seats: { type: Type.STRING },
            purpose: { type: Type.STRING },
            startHour: { type: Type.STRING },
            startMinute: { type: Type.STRING },
            startDay: { type: Type.STRING },
            startMonth: { type: Type.STRING },
            startYear: { type: Type.STRING },
            endHour: { type: Type.STRING },
            endMinute: { type: Type.STRING },
            endDay: { type: Type.STRING },
            endMonth: { type: Type.STRING },
            endYear: { type: Type.STRING },
            fee: { type: Type.STRING },
            issueDay: { type: Type.STRING },
            issueMonth: { type: Type.STRING },
            issueYear: { type: Type.STRING },
            accidentSeats: { type: Type.STRING },
            accidentAmount: { type: Type.STRING },
            accidentFee: { type: Type.STRING },
          }
        }
      }
    });

    const result = JSON.parse(geminiResponse.text || '{}');
    return res.status(200).json(result);
  } catch (error: any) {
    console.error("Extraction Error:", error);
    return res.status(500).json({ error: error.message || "Lỗi xử lý dữ liệu từ AI." });
  }
}

import { InsuranceData } from "../types";

export const extractInsuranceData = async (fileData: { base64?: string, mimeType?: string, url?: string }): Promise<InsuranceData> => {
  try {
    const response = await fetch('/api/extract', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ 
        fileBase64: fileData.base64, 
        mimeType: fileData.mimeType,
        url: fileData.url 
      }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error || "Lỗi máy chủ proxy");
    }

    return await response.json() as InsuranceData;
  } catch (e: any) {
    console.error("Frontend Proxy Error:", e);
    throw new Error(e.message || "Không thể kết nối với dịch vụ trích xuất.");
  }
};

import React, { useState, useCallback, useRef, useMemo, useEffect } from 'react';
import { 
  FileText, 
  Printer, 
  Layout, 
  List, 
  Upload, 
  Settings,
  AlertCircle,
  Loader2,
  Edit3,
  Calendar,
  Clock,
  MousePointer2,
  Type as TypeIcon,
  PlusCircle,
  Trash2,
  Link as LinkIcon,
  Search
} from 'lucide-react';
import { InsuranceData, PrintableElement, TabType } from './types';
import { DEFAULT_ELEMENTS, EMPTY_INSURANCE, LABEL_MAP } from './constants';
import { extractInsuranceData } from './services/geminiService';
import { DraggableItem } from './components/DraggableItem';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('list');
  const [data, setData] = useState<InsuranceData>(EMPTY_INSURANCE);
  const [elements, setElements] = useState<PrintableElement[]>(DEFAULT_ELEMENTS);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isEditingLayout, setIsEditingLayout] = useState(false);
  const [pdfUrl, setPdfUrl] = useState('');

  const containerRef = useRef<HTMLDivElement>(null);

  const applyVehicleTypeLogic = (weightValue: string): string => {
    return weightValue && weightValue.trim() !== '' ? 'Xe tải' : 'Xe ô tô con';
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        try {
          const result = await extractInsuranceData({ base64, mimeType: file.type });
          result.vehicleType = applyVehicleTypeLogic(result.weight);
          setData(result);
        } catch (err: any) {
          setError(err.message || "Không thể trích xuất dữ liệu");
        } finally {
          setIsLoading(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Lỗi khi đọc tệp tin.");
      setIsLoading(false);
    }
  };

  const handleUrlExtract = async () => {
    if (!pdfUrl) return;
    setIsLoading(true);
    setError(null);

    try {
      const result = await extractInsuranceData({ url: pdfUrl });
      result.vehicleType = applyVehicleTypeLogic(result.weight);
      setData(result);
    } catch (err: any) {
      setError(err.message || "Không thể trích xuất từ link này");
    } finally {
      setIsLoading(false);
    }
  };

  const updateElement = useCallback((id: string, updates: Partial<PrintableElement>) => {
    setElements(prev => prev.map(el => el.id === id ? { ...el, ...updates } : el));
  }, []);

  const deleteElement = (id: string) => {
    setElements(prev => prev.filter(el => el.id !== id));
    setSelectedIds(prev => prev.filter(x => x !== id));
  };

  const addCustomElement = () => {
    const newId = `custom-${Date.now()}`;
    const newElement: PrintableElement = {
      id: newId,
      key: 'custom',
      label: 'Nhãn mới',
      content: 'Nội dung...',
      x: 100,
      y: 100,
      fontSize: 16,
      fontWeight: 'bold',
      isVisible: true,
      isCustom: true
    };
    setElements(prev => [...prev, newElement]);
    setSelectedIds([newId]);
    setIsEditingLayout(true);
  };

  const handleSelect = useCallback((id: string, multi: boolean) => {
    setSelectedIds(prev => {
      if (multi) {
        return prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id];
      }
      return [id];
    });
  }, []);

  // Keyboard controls for layout
  useEffect(() => {
    if (!isEditingLayout || selectedIds.length === 0) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      const step = e.shiftKey ? 10 : 1;
      let dx = 0;
      let dy = 0;

      if (e.key === 'ArrowUp') dy = -step;
      else if (e.key === 'ArrowDown') dy = step;
      else if (e.key === 'ArrowLeft') dx = -step;
      else if (e.key === 'ArrowRight') dx = step;
      else if (e.key === 'Delete' || e.key === 'Backspace') {
        selectedIds.forEach(id => {
          const el = elements.find(e => e.id === id);
          if (el?.isCustom) deleteElement(id);
        });
        return;
      }
      else if (e.key === 'Escape') {
        setSelectedIds([]);
        return;
      } else return;

      e.preventDefault();
      setElements(prev => prev.map(el => 
        selectedIds.includes(el.id) 
          ? { ...el, x: Math.max(0, el.x + dx), y: Math.max(0, el.y + dy) } 
          : el
      ));
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isEditingLayout, selectedIds, elements]);

  const handlePrint = () => {
    window.print();
  };

  const handleDataChange = (key: keyof InsuranceData, value: string) => {
    setData(prev => {
      const newData = { ...prev, [key]: value };
      if (key === 'weight') newData.vehicleType = applyVehicleTypeLogic(value);
      return newData;
    });
  };

  const resetLayout = () => {
    setElements(DEFAULT_ELEMENTS);
    setSelectedIds([]);
  };

  const finalQrValue = useMemo(() => data.qrCode || '', [data.qrCode]);

  const renderInput = (key: keyof InsuranceData, placeholder = "...", customLabel?: string) => (
    <div className="flex flex-col space-y-1 w-full">
      <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest ml-1">{customLabel || LABEL_MAP[key] || key}</label>
      <input
        type="text"
        value={data[key] || ''}
        onChange={(e) => handleDataChange(key, e.target.value)}
        className={`w-full px-4 py-2 border border-gray-100 rounded-xl focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all text-sm outline-none font-semibold ${key === 'qrCode' ? 'bg-emerald-50/50 border-emerald-100 italic text-emerald-700' : 'bg-gray-50/50'}`}
        placeholder={placeholder}
      />
    </div>
  );

  const selectedElements = elements.filter(el => selectedIds.includes(el.id));

  const getSpecialValue = (key: string) => {
    const purpose = (data.purpose || '').toLowerCase();
    if (key === 'isBusiness') {
      return (purpose.includes('kinh doanh') && !purpose.includes('không kinh doanh')) ? 'x' : '';
    }
    if (key === 'isNotBusiness') {
      return purpose.includes('không kinh doanh') ? 'x' : '';
    }
    if (key === 'isAgent') {
      return 'x';
    }
    return '';
  };

  return (
    <div className="h-screen flex flex-col bg-gray-50 overflow-hidden relative">
      <header className="no-print bg-white border-b shrink-0 z-50">
        <div className="max-w-full mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-emerald-600 p-2 rounded-lg text-white">
              <FileText size={24} />
            </div>
            <div>
              <h1 className="text-lg font-bold text-gray-800 leading-tight">In Bảo Hiểm Tự Động</h1>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Hệ thống v4.6 • Link Extractor</p>
            </div>
          </div>

          <div className="flex-1 max-w-xl mx-8">
            <div className="relative group">
              <LinkIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-emerald-500 transition-colors" size={18} />
              <input 
                type="text" 
                placeholder="Dán link PDF bảo hiểm vào đây..." 
                value={pdfUrl}
                onChange={(e) => setPdfUrl(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleUrlExtract()}
                className="w-full bg-gray-50 border border-gray-100 rounded-2xl py-2.5 pl-12 pr-28 text-sm outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 focus:bg-white transition-all font-medium"
              />
              <button 
                onClick={handleUrlExtract}
                disabled={!pdfUrl || isLoading}
                className="absolute right-2 top-1/2 -translate-y-1/2 bg-emerald-600 text-white px-4 py-1.5 rounded-xl text-xs font-bold hover:bg-emerald-700 disabled:opacity-50 transition-all flex items-center gap-2"
              >
                {isLoading ? <Loader2 size={14} className="animate-spin" /> : <Search size={14} />}
                TRÍCH XUẤT
              </button>
            </div>
          </div>

          <div className="flex items-center space-x-3">
            <label className="flex items-center space-x-2 px-4 py-2 bg-emerald-50 text-emerald-700 hover:bg-emerald-100 rounded-xl cursor-pointer transition-all text-sm font-bold border border-emerald-100">
              <Upload size={18} />
              <span>Tải file</span>
              <input type="file" className="hidden" accept="application/pdf,image/*" onChange={handleFileUpload} />
            </label>
            <button onClick={handlePrint} className="flex items-center space-x-2 px-5 py-2 bg-gray-800 text-white hover:bg-gray-900 rounded-xl transition-all text-sm font-bold shadow-lg shadow-gray-200 active:scale-95">
              <Printer size={18} />
              <span>In A4</span>
            </button>
          </div>
        </div>
      </header>

      <nav className="no-print bg-white border-b shrink-0 px-6">
        <div className="flex space-x-8">
          {[
